+	ImageData imageData = ImageDataLoader
+			.loadByZoom(new ByteArrayInputStream(streamData), FileFormat.DEFAULT_ZOOM, 100)
+			.element();
+	return zoom -> zoom == 100 ? imageData : null;
+}

